from __future__ import annotations


def bitrix_onec_integration_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bitrix24 ↔ 1С Verification — AI-BIT</title><style>
:root{color-scheme:light;--bg:#f5f6f8;--surface:#fff;--surface2:#fafbfc;--line:#e3e6ea;--text:#17191c;--muted:#70757d;--accent:#5e6ad2;--ok:#16835d;--warn:#a9670b;--bad:#b42318;--mono:ui-monospace,SFMono-Regular,Consolas,monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.45 Inter,Segoe UI,sans-serif}main{max-width:1680px;margin:auto;padding:24px 26px 80px}.head{display:flex;justify-content:space-between;gap:20px;margin-bottom:14px}.eyebrow{font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--accent)}h1{font-size:25px;margin:4px 0}.muted{color:var(--muted)}.actions{display:flex;gap:8px}.btn{border:1px solid var(--line);background:#fff;border-radius:7px;padding:8px 11px;cursor:pointer}.btn.primary{background:#202124;color:#fff;border-color:#202124}.policy,.metrics{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px}.chip,.metric{background:#fff;border:1px solid var(--line);border-radius:9px;padding:8px 11px}.metric span{display:block;color:var(--muted);font-size:10px;text-transform:uppercase}.metric b{font-size:20px}.tabs{display:flex;gap:4px;overflow:auto;border-bottom:1px solid var(--line);margin-bottom:12px}.tab{border:0;background:transparent;padding:9px 11px;color:#666b73;cursor:pointer;border-bottom:2px solid transparent;white-space:nowrap}.tab.active{border-bottom-color:var(--accent);color:var(--text);font-weight:700}.view{display:none}.view.active{display:block}.panel{background:#fff;border:1px solid var(--line);border-radius:10px;overflow:hidden;margin-bottom:10px}.panel-head{display:flex;justify-content:space-between;align-items:center;padding:12px 14px;background:var(--surface2);border-bottom:1px solid var(--line)}.panel-head h2{font-size:14px;margin:0}.count{font:11px var(--mono);color:var(--muted)}table{width:100%;border-collapse:collapse}th,td{padding:9px 11px;text-align:left;border-bottom:1px solid #edf0f2;vertical-align:top}th{font-size:10px;text-transform:uppercase;color:var(--muted);background:#fbfcfd}.mono{font-family:var(--mono);font-size:11px;word-break:break-word}.badge{display:inline-flex;border-radius:999px;padding:3px 7px;font-size:10px;font-weight:800;text-transform:uppercase}.confirmed,.confirmed_candidate,.mapping_in_progress,.ready_for_mapping{background:#e7f6ef;color:var(--ok)}.partial,.candidate,.candidate_found,.in_progress,.waiting_for_structure,.waiting_for_rules,.waiting_for_evidence,.no_evidence{background:#fff3dc;color:var(--warn)}.insufficient_data,.error,.not_found,.discovery_required{background:#fee4e2;color:var(--bad)}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.card{background:#fff;border:1px solid var(--line);border-radius:9px;padding:12px}.card h3{margin:0 0 8px;font-size:13px}.row{display:flex;justify-content:space-between;gap:16px;padding:5px 0;border-bottom:1px solid #eef0f2}.row:last-child{border:0}.empty{padding:28px;text-align:center;color:var(--muted)}.pipeline{display:grid;grid-template-columns:repeat(7,minmax(120px,1fr));gap:8px;padding:12px}.stage{border:1px solid var(--line);border-radius:9px;padding:10px;background:#fff}.stage b{display:block;margin:5px 0}.error-panel{display:none;padding:16px;border:1px solid #f1c5cb;background:#fff7f8;color:#8f2433;border-radius:9px;margin-bottom:10px}.error-panel.show{display:block}@media(max-width:1100px){.pipeline{grid-template-columns:repeat(2,minmax(0,1fr))}}@media(max-width:750px){.grid,.pipeline{grid-template-columns:1fr}.head{display:block}.actions{margin-top:10px}}
</style></head><body><main><div class="head"><div><div class="eyebrow">AI-BIT Enterprise 4.4.0</div><h1>Проверка интеграции Bitrix24 ↔ 1С</h1><div class="muted">Discovery → точки обмена → сущности → поля → данные → техническое заключение</div></div><div class="actions"><button class="btn" id="json">JSON</button><button class="btn primary" id="run">Запустить проверку</button></div></div><div id="error" class="error-panel"></div><div id="policy" class="policy"></div><div id="metrics" class="metrics"></div><nav id="tabs" class="tabs"><button class="tab active" data-view="pipeline">Pipeline</button><button class="tab" data-view="mappings">Сущности</button><button class="tab" data-view="artifacts">Точки интеграции</button><button class="tab" data-view="erp">Паспорт ERP</button><button class="tab" data-view="verification">План проверки</button><button class="tab" data-view="findings">Заключение</button></nav><section id="pipeline" class="view active"></section><section id="mappings" class="view"></section><section id="artifacts" class="view"></section><section id="erp" class="view"></section><section id="verification" class="view"></section><section id="findings" class="view"></section></main><script>
(()=>{'use strict';const q=s=>document.querySelector(s),qa=s=>Array.from(document.querySelectorAll(s)),esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));let data;const badge=v=>`<span class="badge ${esc(v||'insufficient_data')}">${esc(v||'insufficient_data')}</span>`;const panel=(t,b,c='')=>`<div class="panel"><div class="panel-head"><h2>${esc(t)}</h2><span class="count">${esc(c)}</span></div>${b}</div>`;const table=(h,r)=>r.length?`<table><thead><tr>${h.map(x=>`<th>${esc(x)}</th>`).join('')}</tr></thead><tbody>${r.join('')}</tbody></table>`:'<div class="empty">Данных пока нет.</div>';const kv=o=>Object.entries(o||{}).map(([k,v])=>`<div class="row"><span>${esc(k)}</span><b class="mono">${esc(v)}</b></div>`).join('');
function render(){const p=data.verification_pipeline||{},st=p.stages||[],maps=p.entity_mappings||[],arts=p.integration_artifacts||[],calls=p.verification_calls||[],prof=data.onec_profile||{},cfg=prof.configuration||{},mc=prof.metadata_counts||{},sum=data.summary||{};q('#policy').innerHTML=[`mode: ${data.mode}`,`Bitrix write: false`,`1C write: false`,`proposal only: true`].map(x=>`<span class="chip mono">${x}</span>`).join('');q('#metrics').innerHTML=[['Статус',badge(p.status||data.status)],['Этапов',st.length],['Кандидатов',maps.filter(x=>x.onec_candidate).length],['Подтверждено',maps.filter(x=>x.status==='confirmed_candidate').length],['Точек обмена',arts.length],['Findings',sum.findings||0]].map(x=>`<div class="metric"><span>${x[0]}</span><b>${x[1]}</b></div>`).join('');q('#pipeline').innerHTML=panel('Контур проверки',`<div class="pipeline">${st.map((x,i)=>`<div class="stage"><span class="mono">${i+1}. ${esc(x.id)}</span><b>${esc(x.label)}</b>${badge(x.status)}<div class="muted" style="margin-top:8px">${esc(JSON.stringify(x.facts||{}))}</div></div>`).join('')}</div>`,p.version||data.version);q('#mappings').innerHTML=panel('Кандидаты соответствия сущностей',table(['Статус','Связка','Bitrix24','Кандидат 1С','Confidence','Основание'],maps.map(x=>`<tr><td>${badge(x.status)}</td><td><b>${esc(x.label)}</b></td><td class="mono">${esc(x.bitrix_object)}</td><td class="mono">${esc(x.onec_candidate||'—')}</td><td>${Math.round((x.confidence||0)*100)}%</td><td>${esc((x.candidates?.[0]?.reasons||[]).join('; ')||'—')}</td></tr>`)),`${maps.length} mappings`);q('#artifacts').innerHTML=panel('Обнаруженные технические точки интеграции',table(['Категория','Объект 1С','Маркеры','Статус'],arts.map(x=>`<tr><td class="mono">${esc(x.category)}</td><td><b>${esc(x.name)}</b></td><td>${esc((x.markers||[]).join(', '))}</td><td>${badge(x.status)}</td></tr>`)),`${arts.length} artifacts`);q('#erp').innerHTML=panel('Паспорт 1С',`<div class="grid" style="padding:10px"><div class="card"><h3>Конфигурация</h3>${kv({'Наименование':cfg.name||'—','Версия':cfg.version||'—','Поставщик':cfg.vendor||'—','Платформа':cfg.platform_version||'—','Режим':cfg.mode||'—'})}</div><div class="card"><h3>Метаданные</h3>${kv({'Справочники':mc.catalogs||0,'Документы':mc.documents||0,'Регистры сведений':mc.information_registers||0,'Регистры накопления':mc.accumulation_registers||0,'Планы обмена':mc.exchange_plans||0,'Всего':prof.metadata_total||0})}</div></div>`);q('#verification').innerHTML=panel('Следующие read-only проверки',table(['ID','MCP tool','Arguments','Основание'],calls.map(x=>`<tr><td class="mono">${esc(x.id)}</td><td class="mono">${esc(x.name)}</td><td><pre class="mono">${esc(JSON.stringify(x.arguments||{},null,2))}</pre></td><td>${esc(x.reason)}</td></tr>`)),`${calls.length} calls`);const tc=p.technical_conclusion||{},f=p.findings||[];q('#findings').innerHTML=panel('Техническое заключение',`<div style="padding:14px"><div class="row"><span>Статус</span>${badge(tc.status)}</div><div class="row"><span>Подтверждённых отклонений</span><b>${tc.confirmed_findings||0}</b></div><p>${esc(tc.reason||'')}</p></div>`)+panel('Подтверждённые отклонения',table(['Severity','Area','Факт','Действие'],f.map(x=>`<tr><td>${badge(x.severity)}</td><td>${esc(x.area)}</td><td>${esc(x.fact)}</td><td>${esc(x.action)}</td></tr>`)),`${f.length} findings`)}
async function load(run=false){q('#run').disabled=true;q('#error').classList.remove('show');try{const r=await fetch(run?'/bitrix-onec-integration/collect':'/bitrix-onec-integration/latest',{method:run?'POST':'GET',cache:'no-store'});if(!r.ok)throw new Error(await r.text());data=await r.json();render()}catch(e){q('#error').textContent=e.message;q('#error').classList.add('show')}finally{q('#run').disabled=false}}q('#tabs').onclick=e=>{const b=e.target.closest('[data-view]');if(!b)return;qa('.tab,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');q('#'+b.dataset.view).classList.add('active')};q('#run').onclick=()=>load(true);q('#json').onclick=()=>{const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}));a.download='bitrix-onec-verification.json';a.click()};load()})();
</script></body></html>'''
